const rows = $input.all();
const output = [];
for (const item of rows) {
  const row = item.json || {};
  // Check status column - supports multiple naming conventions
  const statusCandidate = row.trigger_status ?? row['trigger status'] ?? row.send_status ?? row['send status'] ?? row.workflow_status ?? row['workflow status'] ?? row.status ?? row.request_status ?? row['request status'] ?? row.switch ?? row.active ?? row.enabled;
  const hasStatusField = statusCandidate !== undefined && statusCandidate !== null && String(statusCandidate).trim() !== '';
  const rawStatus = String(statusCandidate ?? '').trim().toLowerCase();
  // Mandatory status gate: only rows explicitly set to start/continue are processed.
  // Note: 'switch', 'active', 'enabled' columns will also work if set to 'start'/'continue'
  if (!hasStatusField || !['start','continue'].includes(rawStatus)) {
    continue;
  }
  const sentStatusRaw = String(row.sent_status ?? row['sent status'] ?? '').trim().toLowerCase();
  const workflowStatusRaw = String(row.workflow_status ?? row['workflow status'] ?? '').trim().toLowerCase();
  if (sentStatusRaw === 'done' || sentStatusRaw === 'finish' || workflowStatusRaw === 'done' || workflowStatusRaw === 'completed') {
    continue;
  }
  const requestId = String(row.request_id || row.requestId || '').trim();
  const fallbackKey = [row.company_name || row.company || '', row.industry || '', row.target_audience || row.audience || '', row.company_link || row.website || row.url || ''].join('|').trim();
  const rowNumber = String(row.row_number || row.rowNumber || '').trim();
  const key = requestId || (rowNumber ? `row:${rowNumber}` : fallbackKey);
  if (!key) {
    continue;
  }
  output.push({ json: { ...row, __intake_key: key, __trigger_status: rawStatus || (hasStatusField ? '' : 'start') } });
  // Single-item queue mode: process only one intake row per polling run.
  if (output.length >= 1) {
    break;
  }
}
return output;

const input = $json || {};
// Support multiple status column naming conventions
const statusSource = input.trigger_status || input['trigger status'] || input.send_status || input['send status'] || input.workflow_status || input['workflow status'] || input.status || input.request_status || input['request status'] || input.switch || input.active || input.enabled || input.__trigger_status || '';
const statusRaw = String(statusSource).trim().toLowerCase();
const normalizedStatus = ['start','continue','pause','pending','done','finish'].includes(statusRaw) ? statusRaw : (statusRaw ? 'pending' : 'start');
return [{ json: {
  ...input,
  request_id: input.request_id || input.requestId || '',
  company_name: input.company_name || input.company || '',
  industry: input.industry || '',
  target_audience: input.target_audience || input.audience || '',
  company_link: input.company_link || input.website || input.url || '',
  writer_task: input.writer_task || input.prompt || input['prompt text'] || input.prompt_text || input.prompt_ar || input['prompt ar'] || '',
  trigger_status: normalizedStatus,
  sent_status: input.sent_status || input['sent status'] || input.delivery_status || 'pending',
  source: input.source || 'sheet_intake',
  approval_status: input.approval_status || 'approved'
} }];

const input = $json || {};
const raw = (input.body && typeof input.body === 'object') ? input.body : input;
const telegramText = raw.message?.text || raw.edited_message?.text || raw.text || '';
const telegramChatId = raw.message?.chat?.id || raw.edited_message?.chat?.id || raw.chat?.id || input.telegram_chat_id || '';
const isTelegram = Object.prototype.hasOwnProperty.call(raw, 'update_id') || !!telegramChatId;
const normalizedText = String(telegramText || '').trim();
const replyContextText = String(raw.message?.reply_to_message?.text || raw.edited_message?.reply_to_message?.text || '').trim();
const parsingText = [normalizedText, replyContextText].filter(Boolean).join('\n');
const normalizeCmd = (v) => String(v || '').toLowerCase().replace(/[^\p{L}\p{N}\s]/gu, ' ').replace(/\s+/g, ' ').trim();
const commandText = normalizeCmd(normalizedText);
const isGenerateCommand = /(?:^|\s)(confirm|generate|ابدأ|ابدا|تأكيد|اعتماد)(?:\s+التنفيذ)?(?:\s|$)/i.test(commandText);
const topicFromTelegram = isGenerateCommand ? '' : normalizedText.replace(/^\/(start|blog|write)\b/i, '').trim();
const approvalFromTelegram = /approved|approve|اعتماد|موافق|موافقة/i.test(normalizedText) ? 'approved' : '';
const draftEmailFromTelegram = /send\s+draft\s+email|draft\s+email|مسودة\s*ايميل|مسودة\s*بريد/i.test(normalizedText);
let topic = raw.topic || raw.title_ar || raw.title_en || topicFromTelegram || raw.company_name || "موضوع جديد";
const now = new Date();
const pad = (n) => String(n).padStart(2, '0');
const generatedRequestId = `REQ-${now.getFullYear()}${pad(now.getMonth()+1)}${pad(now.getDate())}-${pad(now.getHours())}${pad(now.getMinutes())}${pad(now.getSeconds())}-${Math.random().toString(36).slice(2,6).toUpperCase()}`;
const requestId = String(raw.request_id || raw.id || generatedRequestId);
const intake = {
