};
const parseInlineFields = (text) => {
  const t = String(text || '');
  const c = t.replace(/\s+/g, ' ').trim();
  const clean = (v) => String(v || '').trim().replace(/[،,;|]+$/g, '').trim();
  const pick = (...patterns) => {
    for (const p of patterns) {
      const m = t.match(p);
      if (!m) continue;
      for (let i = 1; i < m.length; i++) {
        const v = clean(m[i]);
        if (v) return v;
