  };
  const website = pick(/((?:https?:\/\/|www\.)[^\s،,|]+)/i, /([a-z0-9][a-z0-9-]*\.[a-z]{2,}(?:\/[^\s،,|]*)?)/i);
  const extractByLabelSpan = (sourceText, labelRegexMap) => {
    const hits = [];
    for (const row of labelRegexMap) {
      const re = new RegExp(row.re.source, row.re.flags);
      let m;
      while ((m = re.exec(sourceText)) !== null) {
        hits.push({ key: row.key, idx: m.index, len: String(m[0] || '').length });
      }
    }
    hits.sort((a, b) => a.idx - b.idx);
    const out = {};
    for (let i = 0; i < hits.length; i++) {
      const h = hits[i];
      if (out[h.key]) continue;
      const nextIdx = i + 1 < hits.length ? hits[i + 1].idx : sourceText.length;
      const rawVal = sourceText.slice(h.idx + h.len, nextIdx).replace(/^\s*[:：\-]?\s*/, '');
      const v = clean(rawVal);
      if (v) out[h.key] = v;
    }
    return out;
  };
  const cutBefore = (value, markers) => {
    const raw = clean(value);
    if (!raw) return '';
    let idx = -1;
    for (const m of markers) {
      const p = raw.search(m);
      if (p >= 0 && (idx < 0 || p < idx)) idx = p;
    }
    return clean(idx >= 0 ? raw.slice(0, idx) : raw);
  };
  const fallbackCompany = (() => {
    const m = c.match(/(?:اسم\s*(?:النشاط\s*\/\s*الشركة|النشاط|الشركة)|الشركة)\s*[:：-]?\s*(.+)/i);
    return m ? cutBefore(m[1], [/(?:اسم\s*القطاع|القطاع|المجال)/i, /(?:الجمهور\s*المستهدف|الفئة\s*المستهدفة|الجمهور|الفئة)/i, /(?:رابط\s*الموقع|الموقع|الرابط)/i, /(?:https?:\/\/|www\.)/i]) : '';
  })();
  const fallbackIndustry = (() => {
    const m = c.match(/(?:اسم\s*القطاع|القطاع|المجال)\s*[:：-]?\s*(.+)/i);
    return m ? cutBefore(m[1], [/(?:الجمهور\s*المستهدف|الفئة\s*المستهدفة|الجمهور|الفئة)/i, /(?:رابط\s*الموقع|الموقع|الرابط)/i, /(?:https?:\/\/|www\.)/i]) : '';
  })();
  const fallbackAudience = (() => {
    const m = c.match(/(?:الجمهور\s*المستهدف|الفئة\s*المستهدفة|الجمهور|الفئة)\s*[:：-]?\s*(.+)/i);
    return m ? cutBefore(m[1], [/(?:رابط\s*الموقع|الموقع|الرابط)/i, /(?:https?:\/\/|www\.)/i]) : '';
  })();
  const labelSpans = extractByLabelSpan(c, [
    { key: 'company_name', re: /(?:اسم\s*(?:النشاط\s*\/\s*الشركة|النشاط|الشركة)|الشركة)/gi },
    { key: 'industry', re: /(?:اسم\s*القطاع|القطاع|المجال)/gi },
    { key: 'target_audience', re: /(?:الجمهور\s*المستهدف|الفئة\s*المستهدفة|الجمهور|الفئة)/gi },
    { key: 'company_link', re: /(?:رابط\s*الموقع|الموقع|الرابط)/gi },
    { key: 'topic', re: /(?:موضوع\s*المحتوى|الموضوع|العنوان)/gi },
