    target_audience: pick(/(?:الجمهور\s*المستهدف|الفئة\s*المستهدفة|الجمهور|الفئة)\s*[:：-]?\s*([^\n،,|]+)/i) || fallbackAudience || labelSpans.target_audience || '',
    company_link: website || clean(labelSpans.company_link || ''),
    topic: pick(/(?:موضوع\s*المحتوى|الموضوع|العنوان)\s*[:：-]?\s*([^\n،,|]+)/i) || clean(labelSpans.topic || ''),
  };
};
const interviewPairs = isTelegram ? parseInterviewPairs(parsingText) : {};
